-- tedw_release_summary
VALUES (
'
<span style="background-color: #9D0208; color: white; font-weight: bold; font-size: 18px; padding: 5px; display: inline-block; text-decoration: underline;">Release Summary - 11/18/2024 :</span>
<h4 style="margin-top: 0;">This release includes the following:</h4>
<ol>
    <li>Enhancements - 8
        <ul>
			<li>Datamart enhancements - Updated logic in tbroker_summary table to load Month to Date(MTD) values instead of Year to date(YTD) values.</li>
			<li>Datamart enhancements - Added the following columns to tbroker_summary table. </li>
			1) ytd_policy_expiring_ct<br>
                        2) ytd_policy_renewal_accepted_ct<br>
                        3) ytd_policy_renewal_ct<br>
			4) ytd_policy_renewal_offered_ct<br>
                        5) ytd_policy_renewal_offered_over_50k_ct<br>
                        6) ytd_policy_renewal_offered_premium_amt<br>
			7) ytd_policy_renewal_offered_expiring_premium_amt<br>
                        8) ytd_policy_expiring_premium_amt<br>
                        9) ytd_policy_renewal_premium_amt			
			<li>External Integrations - Implemented minor code fixes to hubspot feed for calculating renewal retention percentage.</li>
			<li>External Integrations - Implemented minor code fixes for IVANS home associated with loss of use and contents coverages.</li>
			<li>Created view to capture TICO Place codes data.</li>
			<li>Backfilled wildfire protection data using information gathered from manual forms for the Redzone feed. </li>
			<li>Added 2 new columns lifetime_claim_ct and lifetime_loss_incurred_amt to tpolicy & tquote table.</li>
			<li>Added new column issued_quote_history_sk to tquote table.</li>
			<li>Added new column last_inspection_dt to thome_coverage and tquote_home_coverage table.</li>
		</ul>
    </li>
    <li>Bug tickets - 13
        <ul>
			<li>Updated stored procedure logic to populate policy_history_sk for OS policies in tpolicy_transaction table.</li>
			<li>Updated stored procedure logic to populate internal coverage for Clean Risk Loss Recoupment to aslob 192 from 211 in tinternal_coverage table.</li>
			<li>Updated tpel_driver_incident & tquote_pel_driver_incident table stored procedure to populate pel_driver_sk & quote_pel_driver_sk which were null.</li>
			<li>Deleted 22 brokers from Metal and EDW as per the licensing team request. These brokers were created in error due to a Metal issue. The issue is no longer happening.</li>
			<li>Deleted duplicate cancellation transactions for 10 old migrated policies. </li>
			<li>Deleted duplicate cancellation transactions for 2 policies.</li>
			<li>Updated policy status from bound to issued status for 5 non NY policies.</li>
			<li>Updated stats premium associated with transaction sequence =  0 for one policy.</li>
			<li>Resolved 2 tickets associated with repushing of policies associated with data fixes applied on IVANS.</li>
			<li>Resolved 1 ticket associated with updating original_policy_effective_dt and subscriber_contribution_dt for one policy.</li>
			<li>Resolved 1 ticket associated with updating relationship_to_insured for one policy.</li>
		</ul>
    </li>
</ol>
'
,'Yes'
,'2024-11-18'
,getdate()
,getdate()
)
;

-- tedw_release_note

